    };
  }
};

import React from 'react';

interface MarkdownRendererProps {
  content: string;
}

export const MarkdownRenderer: React.FC<MarkdownRendererProps> = ({ content }) => {
  const escapeHtml = (text: string) => {
    return text
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;")
      .replace(/'/g, "&#039;");
  };

  const cleanText = (text: string) => {
    return escapeHtml(text).replace(/\*\*/g, '').replace(/##/g, '');
  };

  const processLine = (line: string, index: number) => {
    if (line.startsWith('---')) {
      return <hr key={index} className="my-4 border-slate-700" />;
    }

    if (line.includes('TRẠNG THÁI HỆ THỐNG') || line.includes('NỘI DUNG TƯ VẤN') || line.includes('KHUYẾN NGHỊ TIẾP THEO')) {
      const headerText = line.replace(/\*\*/g, '').replace(/##/g, '').replace(/:/g, '').trim();
      return <h3 key={index} className="text-emerald-400 font-bold mt-4 mb-2 tracking-wide uppercase">{headerText}</h3>;
    }

    if (line.trim().startsWith('- ') || line.trim().startsWith('* ')) {
      const text = line.trim().substring(2);
      return <li key={index} className="ml-4 mb-1 text-slate-300 list-disc marker:text-emerald-600" dangerouslySetInnerHTML={{__html: cleanText(text)}} />;
    }

    if (line.trim().length > 0) {
      return <p key={index} className="mb-2 text-slate-200 leading-relaxed" dangerouslySetInnerHTML={{__html: cleanText(line)}} />;
    }

    return <div key={index} className="h-2"></div>;
  };

  return (
    <div className="markdown-body text-sm md:text-base font-sans">
      {content.split('\n').map((line, idx) => processLine(line, idx))}
    </div>
  );
};

