import React, { useState } from 'react';
import { UserChat } from './components/UserChat';
import { AdminDashboard } from './components/AdminDashboard';
import { PaymentModal } from './components/PaymentModal';
import { UserProfile, INITIAL_USERS, AgentConfig, INITIAL_AGENT_CONFIGS, PlanConfig, INITIAL_PLAN_CONFIGS, ViewMode, UserLevel, AgentType } from './types';

const App: React.FC = () => {
  const [viewMode, setViewMode] = useState<ViewMode>('USER');
  const [users, setUsers] = useState<UserProfile[]>(INITIAL_USERS);
  const [currentUser, setCurrentUser] = useState<UserProfile>(INITIAL_USERS[1]); // Default to Guest
  const [agentConfigs, setAgentConfigs] = useState<Record<AgentType, AgentConfig>>(INITIAL_AGENT_CONFIGS);
  const [planConfigs, setPlanConfigs] = useState<Record<UserLevel, PlanConfig>>(INITIAL_PLAN_CONFIGS);

  // Payment State
  const [showPaymentModal, setShowPaymentModal] = useState(false);

  const handleCommand = (cmd: string) => {
    const trimmedCmd = cmd.trim().toLowerCase();
    if (trimmedCmd === '/admin') setViewMode('ADMIN');
    else if (trimmedCmd === '/user') setViewMode('USER');
    else if (trimmedCmd.startsWith('/switch ')) {
       const userId = cmd.split(' ')[1];
       const foundUser = users.find(u => u.id === userId);
       if (foundUser) setCurrentUser(foundUser);
    }
  };

  const deductCredit = () => {
    if (currentUser.level === 'Enterprise') return;
    const updatedUser = { ...currentUser, credits: Math.max(0, currentUser.credits - 1) };
    setCurrentUser(updatedUser);
    setUsers(prev => prev.map(u => u.id === currentUser.id ? updatedUser : u));
  };

  const handleUpdateUser = (updatedUser: UserProfile) => {
    setUsers(prev => prev.map(u => u.id === updatedUser.id ? updatedUser : u));
    if (currentUser.id === updatedUser.id) setCurrentUser(updatedUser);
  };

  const handleAddUser = (newUser: UserProfile) => setUsers(prev => [...prev, newUser]);

  const handleDeleteUser = (userId: string) => {
    setUsers(prev => prev.filter(u => u.id !== userId));
    if (currentUser.id === userId) setCurrentUser(users[0]);
  };

  const handlePaymentSuccess = (planId: string, amount: number) => {
    // Determine credits and level based on plan
    let newLevel = currentUser.level;
    let addedCredits = 0;

    if (planId === 'Gold') {
        newLevel = 'Gold';
        addedCredits = 500;
    } else if (planId === 'Enterprise') {
        newLevel = 'Enterprise';
        addedCredits = 9999;
    }

    const updatedUser: UserProfile = {
        ...currentUser,
        level: newLevel,
        credits: currentUser.level === 'Enterprise' ? currentUser.credits : currentUser.credits + addedCredits,
        totalSpent: currentUser.totalSpent + amount
    };

    setCurrentUser(updatedUser);
    setUsers(prev => prev.map(u => u.id === currentUser.id ? updatedUser : u));
  };

  return (
    <>
        {viewMode === 'USER' ? (
            <UserChat 
                currentUser={currentUser} 
                deductCredit={deductCredit} 
                onCommand={handleCommand} 
                agentConfigs={agentConfigs} 
                onTriggerUpgrade={() => setShowPaymentModal(true)}
            />
        ) : (
            <AdminDashboard 
                users={users} 
                onCommand={handleCommand} 
                onUpdateUser={handleUpdateUser} 
                onAddUser={handleAddUser} 
                onDeleteUser={handleDeleteUser} 
                agentConfigs={agentConfigs} 
                onUpdateAgentConfigs={setAgentConfigs} 
                planConfigs={planConfigs} 
                onUpdatePlanConfigs={setPlanConfigs} 
            />
        )}

        <PaymentModal 
            isOpen={showPaymentModal}
            onClose={() => setShowPaymentModal(false)}
            plans={planConfigs}
            onSuccess={handlePaymentSuccess}
            currentLevel={currentUser.level}
        />
    </>
  );
};

export default App;

