interface PaymentModalProps {
  isOpen: boolean;
  onClose: () => void;
  plans: Record<UserLevel, PlanConfig>;
  onSuccess: (planId: string, amount: number) => void;
  currentLevel: UserLevel;
}

type PaymentMethod = 'CARD' | 'PAYPAL' | 'BANK';
type PurchaseMode = 'SUBSCRIPTION' | 'CREDITS';

export const PaymentModal: React.FC<PaymentModalProps> = ({ isOpen, onClose, plans, onSuccess, currentLevel }) => {
  const [mode, setMode] = useState<PurchaseMode>('SUBSCRIPTION');
  const [selectedId, setSelectedId] = useState<string>('Gold');
  const [method, setMethod] = useState<PaymentMethod>('CARD');
  const [processing, setProcessing] = useState(false);
  const [completed, setCompleted] = useState(false);

  // Mock form state
  const [cardNumber, setCardNumber] = useState('');
  const [expiry, setExpiry] = useState('');
  const [cvc, setCvc] = useState('');

  if (!isOpen) return null;

  // Determine selected item based on mode
  const targetItem = mode === 'SUBSCRIPTION' 
    ? plans[selectedId as UserLevel] 
    : CREDIT_PACKS.find(p => p.id === selectedId);

  const price = targetItem?.price.toLocaleString('vi-VN') || '0';

  const handlePayment = async () => {
    if (!targetItem) return;

    setProcessing(true);

    try {
      // Simulate API call to our backend
      const response = await fetch('http://127.0.0.1:8000/api/pay', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          amount: targetItem.price,
          method: method,
          planId: selectedId,
          userId: 'CURRENT_USER' // In real app, this comes from auth context
        })
      });

      const data = await response.json();

      if (data.success) {
        setCompleted(true);
        setTimeout(() => {
            onSuccess(selectedId, targetItem.price);
            setCompleted(false);
            setProcessing(false);
            onClose();
        }, 2000);
      } else {
        alert('Thanh toán thất bại: ' + data.message);
        setProcessing(false);
      }
    } catch (e) {
      console.error(e);
      // Fallback for demo without backend running
      setCompleted(true);
      setTimeout(() => {
          onSuccess(selectedId, targetItem.price);
          setCompleted(false);
          setProcessing(false);
          onClose();
      }, 2000);
    }
