import React, { useState, useEffect, useRef } from 'react';
import { Send, Scale, ShieldCheck, BrainCircuit, Cpu, Zap, BookOpen, Terminal, Activity, HelpCircle, ArrowRight, Lock, X, AlertTriangle, Wifi, WifiOff, ChevronDown, Check, LayoutGrid, Edit2, Save, Shield } from 'lucide-react';
import { Message, AgentStage, UserProfile, AgentType, ResponseStyle, AgentConfig, AGENTS_LIST } from '../types';
import { sendMessageToGemini } from '../services/geminiService';
import { MarkdownRenderer } from './MarkdownRenderer';
import { CreditModal } from './CreditModal';

interface UserChatProps {
  currentUser: UserProfile;
  deductCredit: () => void;
  onCommand: (cmd: string) => void;
  agentConfigs: Record<AgentType, AgentConfig>;
  onTriggerUpgrade: (mode?: 'SUBSCRIPTION' | 'CREDITS') => void;
}

export const UserChat: React.FC<UserChatProps> = ({ currentUser, deductCredit, onCommand, agentConfigs, onTriggerUpgrade }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputText, setInputText] = useState('');
  const [agentStage, setAgentStage] = useState<AgentStage>(AgentStage.IDLE);
  const [showCreditModal, setShowCreditModal] = useState(false);
  const [isLanding, setIsLanding] = useState(true);
  const [selectedAgent, setSelectedAgent] = useState<AgentType>('GENERAL');
  const [showAgentMenu, setShowAgentMenu] = useState(false);
  const [responseStyle, setResponseStyle] = useState<ResponseStyle>('CONCISE');

  // Editing State
  const [editingMsgId, setEditingMsgId] = useState<string | null>(null);
  const [editTempText, setEditTempText] = useState('');

  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!isLanding) messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, agentStage, isLanding]);

  const processAIResponse = async (prompt: string, historyMessages: Message[]) => {
    deductCredit();
    setAgentStage(AgentStage.ROUTING);
    await new Promise(r => setTimeout(r, 800));
    setAgentStage(AgentStage.SPECIALIST);

    const apiHistory = historyMessages.map(m => ({ role: m.role, parts: [{ text: m.text }] }));
    const activeConfig = selectedAgent !== 'GENERAL' ? agentConfigs[selectedAgent] : undefined;

    try {
      const response = await sendMessageToGemini(prompt, apiHistory, selectedAgent, responseStyle, activeConfig, currentUser.level);

      const parts = response.text.split("💡 GỢI Ý TIẾP THEO");
      const cleanText = parts[0].trim();
      const suggestions = parts[1] ? parts[1].split('\n').filter(l => l.trim().startsWith('-')).map(l => l.replace('-','').trim()).slice(0, 4) : [];

      setAgentStage(AgentStage.REVIEWING);
      await new Promise(r => setTimeout(r, 800));

      const botMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: cleanText,
        suggestedQuestions: suggestions,
        timestamp: new Date(),
        metadata: { agentUsed: selectedAgent, source: response.source === 'BACKEND' ? 'SPECIALIZED_KB' : 'GENERAL_AI' }
      };
      setMessages(prev => [...prev, botMsg]);
      setAgentStage(AgentStage.IDLE);
    } catch (e) {
      setAgentStage(AgentStage.IDLE);
    }
  };

  const handleSendMessage = async (textOverride?: string) => {
    const textToSend = textOverride || inputText;
    if (!textToSend.trim()) return;

    if (textToSend.startsWith('/')) {
      onCommand(textToSend);
      setInputText('');
      return;
    }

    if (currentUser.credits <= 0) {
      setShowCreditModal(true);
      return;
    }

    setIsLanding(false);
    const userMsg: Message = { id: Date.now().toString(), role: 'user', text: textToSend, timestamp: new Date() };
    setMessages(prev => [...prev, userMsg]);
    setInputText('');

    await processAIResponse(textToSend, messages);
  };

  const startEditing = (msg: Message) => {
    setEditingMsgId(msg.id);
    setEditTempText(msg.text);
  };

  const cancelEditing = () => {
    setEditingMsgId(null);
    setEditTempText('');
  };

  const submitEdit = async () => {
    if (!editingMsgId || !editTempText.trim()) return;

    const msgIndex = messages.findIndex(m => m.id === editingMsgId);
    if (msgIndex === -1) return;

    if (currentUser.credits <= 0) {
        setShowCreditModal(true);
        return;
    }

    const newText = editTempText;
    setEditingMsgId(null);
    setEditTempText('');

    // Slice history up to the edited message (remove everything after it)
    const historyMessages = messages.slice(0, msgIndex);

    const newUserMsg: Message = { 
        ...messages[msgIndex], 
        text: newText, 
        timestamp: new Date() 
    };

    // Update state: History + New User Msg
    setMessages([...historyMessages, newUserMsg]);

    // Trigger AI with the truncated history
    await processAIResponse(newText, historyMessages);
  };

  const activeLabel = AGENTS_LIST.find(a => a.id === selectedAgent)?.label || 'Luật sư Tổng hợp';

  if (isLanding) {
    return (
      <div className="min-h-screen bg-[#020617] text-white flex flex-col relative font-inter overflow-hidden">
        <div className="absolute inset-0 bg-[linear-gradient(to_right,#0f172a_1px,transparent_1px),linear-gradient(to_bottom,#0f172a_1px,transparent_1px)] bg-[size:4rem_4rem] [mask-image:radial-gradient(ellipse_60%_50%_at_50%_0%,#000_70%,transparent_100%)] pointer-events-none"></div>
        <header className="p-6 flex justify-between items-center z-10">
            <div className="font-bold text-xl font-mono">ecolaw<span className="text-emerald-500">.ai</span></div>
            <div className="flex items-center gap-4">
                <button 
                  onClick={() => onCommand('/admin')}
                  className="hidden md:flex items-center gap-2 px-3 py-1.5 text-xs font-bold text-slate-400 hover:text-white border border-transparent hover:border-slate-700 rounded-lg transition-all"
                >
                  <LayoutGrid size={14}/> ADMIN PORTAL
                </button>
                <div className="hidden md:flex bg-slate-900 rounded-full p-1 border border-slate-800">
                   <button onClick={() => setResponseStyle('CONCISE')} className={`px-3 py-1 rounded-full text-xs ${responseStyle === 'CONCISE' ? 'bg-emerald-600 text-white' : 'text-slate-400'}`}>Ngắn gọn</button>
                   <button onClick={() => setResponseStyle('DEEP')} className={`px-3 py-1 rounded-full text-xs ${responseStyle === 'DEEP' ? 'bg-emerald-600 text-white' : 'text-slate-400'}`}>Chuyên sâu</button>
                </div>
                <div className="text-right">
                    <div className="text-xs font-bold text-slate-300">{currentUser.name}</div>
                    <div onClick={() => onTriggerUpgrade('CREDITS')} className="text-[10px] text-emerald-400 cursor-pointer hover:underline">{currentUser.credits} CR (Nạp thêm)</div>
                </div>
            </div>
        </header>
        <main className="flex-1 flex flex-col items-center justify-center px-4 relative z-10 pb-20">
            <div className="text-center mb-10">
                <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-emerald-950/30 border border-emerald-900 text-emerald-400 text-xs font-mono mb-4"><span className="relative flex h-2 w-2"><span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-emerald-400 opacity-75"></span><span className="relative inline-flex rounded-full h-2 w-2 bg-emerald-500"></span></span> SYSTEM ONLINE v2.6 (2026 UPDATE)</div>
                <h1 className="text-6xl font-bold mb-4">ecolaw<span className="text-emerald-500">.ai</span></h1>
                <p className="text-slate-400 text-lg max-w-2xl mx-auto">Hệ thống tư vấn pháp lý <span className="text-emerald-400 font-bold">Real-time</span> được hỗ trợ bởi trí tuệ nhân tạo đa tác nhân.</p>
            </div>
            <div className="w-full max-w-2xl">
                 <div className="flex justify-center mb-6">
                    <div className="bg-slate-900/80 p-1 rounded-full border border-slate-800 flex">
                        <button onClick={() => setResponseStyle('CONCISE')} className={`px-4 py-2 rounded-full text-sm font-bold flex items-center gap-2 transition-all ${responseStyle === 'CONCISE' ? 'bg-emerald-600 text-white' : 'text-slate-400 hover:text-white'}`}><Zap size={14}/> Ngắn gọn</button>
                        <button onClick={() => setResponseStyle('DEEP')} className={`px-4 py-2 rounded-full text-sm font-bold flex items-center gap-2 transition-all ${responseStyle === 'DEEP' ? 'bg-slate-800 text-white' : 'text-slate-400 hover:text-white'}`}><BookOpen size={14}/> Chuyên sâu</button>
                    </div>
                </div>
                <form onSubmit={(e) => { e.preventDefault(); handleSendMessage(); }} className="relative">
                    <input autoFocus type="text" value={inputText} onChange={e => setInputText(e.target.value)} placeholder={`[AGENT: ${activeLabel}] Nhập lệnh hoặc câu hỏi...`} className="w-full py-5 pl-6 pr-32 bg-slate-900/80 backdrop-blur border border-slate-700 rounded-xl text-white font-mono focus:border-emerald-500 focus:outline-none"/>
                    <button type="submit" className="absolute right-2 top-2 bottom-2 bg-emerald-600 hover:bg-emerald-500 text-white font-bold rounded-lg px-4 flex items-center gap-2">RUN <Activity size={16}/></button>
                </form>
                <div className="mt-8 text-center text-xs text-slate-500 uppercase tracking-widest mb-4">Gợi ý tìm kiếm (2026)</div>
                <div className="flex flex-wrap justify-center gap-2">
                    {["Luật Đất đai: Quy định mới 2026", "Tích hợp Căn cước & VNeID 2026", "Luật Trật tự an toàn giao thông 2026", "Mức lương tối thiểu vùng 2026", "Luật Kinh doanh Bất động sản 2026", "Chính sách Thuế TNCN sửa đổi 2026"].map((t, i) => (
                        <button key={i} onClick={() => setInputText(t)} className="px-3 py-1.5 rounded-lg border border-slate-800 bg-slate-900/50 text-slate-400 text-xs hover:border-emerald-500/30 hover:text-emerald-400 transition-colors">{t}</button>
                    ))}
                </div>
                <div className="mt-8 flex flex-wrap justify-center gap-2">
                     {AGENTS_LIST.map(a => { const Icon = a.icon; return (
                         <button key={a.id} onClick={() => setSelectedAgent(a.id)} className={`flex items-center gap-2 px-4 py-2 rounded-full border text-xs transition-all ${selectedAgent === a.id ? 'bg-slate-800 border-emerald-500 text-emerald-400' : 'bg-slate-900 border-slate-800 text-slate-500 hover:border-slate-600'}`}><Icon size={14}/> {a.label}</button>
                     )})}
                </div>
            </div>
            <div className="absolute bottom-8 text-xs text-slate-600 font-mono">ECOLAW.AI SYSTEM © 2026. ALL RIGHTS RESERVED.</div>
        </main>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-screen bg-[#020617] font-inter text-slate-200">
      <header className="h-16 border-b border-slate-800 bg-slate-950 flex items-center justify-between px-6 z-20">
         <div className="font-bold text-xl font-mono cursor-pointer" onClick={() => setIsLanding(true)}>ecolaw<span className="text-emerald-500">.ai</span></div>
         <div className="flex items-center gap-4">
             <div className="hidden md:flex bg-slate-900 rounded-full p-1 border border-slate-800">
                <button onClick={() => setResponseStyle('CONCISE')} className={`px-3 py-1 rounded-full text-xs ${responseStyle === 'CONCISE' ? 'bg-emerald-600 text-white' : 'text-slate-400'}`}><Zap size={12}/> Nhanh</button>
                <button onClick={() => setResponseStyle('DEEP')} className={`px-3 py-1 rounded-full text-xs ${responseStyle === 'DEEP' ? 'bg-emerald-600 text-white' : 'text-slate-400'}`}><BookOpen size={12}/> Sâu</button>
             </div>
             <div className="relative">
                <button onClick={() => setShowAgentMenu(!showAgentMenu)} className="flex items-center gap-2 px-3 py-1.5 bg-slate-900 border border-slate-700 rounded-full text-sm hover:border-emerald-500 transition-colors"><BrainCircuit size={16} className="text-emerald-500"/> {activeLabel} <ChevronDown size={14}/></button>
                {showAgentMenu && (
                    <div className="absolute top-full right-0 mt-2 w-56 bg-slate-900 border border-slate-700 rounded-xl shadow-xl overflow-hidden z-30">
                        {AGENTS_LIST.map(a => (
                            <button key={a.id} onClick={() => {setSelectedAgent(a.id); setShowAgentMenu(false)}} className={`w-full text-left px-4 py-2 text-sm hover:bg-slate-800 flex items-center justify-between ${selectedAgent === a.id ? 'text-emerald-400' : 'text-slate-300'}`}>{a.label} {selectedAgent === a.id && <Check size={14}/>}</button>
                        ))}
                    </div>
                )}
             </div>
             <button onClick={() => onCommand('/admin')} className="text-slate-400 hover:text-white p-2 rounded-full hover:bg-slate-800 transition-colors" title="Admin Dashboard"><LayoutGrid size={20}/></button>
             <button onClick={() => onTriggerUpgrade('SUBSCRIPTION')} className="bg-emerald-900/30 text-emerald-400 text-xs px-3 py-1.5 rounded-lg border border-emerald-500/30 hover:bg-emerald-900/50 transition-colors font-mono font-bold">
                 UPGRADE
             </button>
         </div>
      </header>
      <div className="flex-1 overflow-y-auto p-4 md:p-8 space-y-6">
        {messages.map(msg => (
            <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} group`}>
                {msg.role === 'model' && <div className="w-8 h-8 rounded bg-slate-900 border border-slate-700 flex items-center justify-center mr-3 text-emerald-500"><Cpu size={18}/></div>}
                <div className={`max-w-[85%] rounded-2xl p-4 md:p-6 border relative ${msg.role === 'user' ? 'bg-emerald-900/20 border-emerald-500/30 text-emerald-100 rounded-tr-sm' : 'bg-slate-900/80 border-slate-800 text-slate-200 rounded-tl-sm'}`}>

                    {editingMsgId === msg.id ? (
                        <div className="flex flex-col gap-2 min-w-[280px] md:min-w-[400px]">
                            <textarea 
                                value={editTempText} 
                                onChange={e => setEditTempText(e.target.value)}
                                className="w-full bg-slate-950/50 text-emerald-100 p-3 rounded-xl border border-emerald-500/50 focus:outline-none focus:ring-1 focus:ring-emerald-500 text-sm font-mono leading-relaxed resize-none"
                                rows={Math.max(3, editTempText.split('\n').length)}
                                autoFocus
                            />
                            <div className="flex justify-end gap-2">
                                <button onClick={cancelEditing} className="px-3 py-1.5 text-xs font-bold text-slate-400 hover:text-white bg-slate-900 rounded-lg flex items-center gap-1 transition-colors"><X size={14}/> Cancel</button>
                                <button onClick={submitEdit} className="px-3 py-1.5 text-xs font-bold text-white bg-emerald-600 hover:bg-emerald-500 rounded-lg flex items-center gap-1 transition-colors"><Save size={14}/> Save & Run</button>
                            </div>
                        </div>
                    ) : (
                        <>
                            {msg.role === 'user' ? <p className="whitespace-pre-wrap">{msg.text}</p> : <MarkdownRenderer content={msg.text} />}

                            {msg.role === 'user' && (
                                <button 
                                    onClick={() => startEditing(msg)}
                                    className="absolute -left-10 top-2 p-2 text-slate-600 hover:text-emerald-400 opacity-0 group-hover:opacity-100 transition-all bg-slate-900/50 rounded-full"
                                    title="Chỉnh sửa tin nhắn"
                                >
                                    <Edit2 size={14}/>
                                </button>
                            )}

                            {msg.suggestedQuestions && msg.suggestedQuestions.length > 0 && (
                                <div className="mt-4 pt-3 border-t border-slate-800">
                                     <div className="text-xs text-slate-500 uppercase tracking-widest mb-2 flex items-center gap-1"><HelpCircle size={12}/> Gợi ý tiếp theo</div>
                                     <div className="flex flex-wrap gap-2">
                                        {msg.suggestedQuestions.map((q, i) => (
                                            <button key={i} onClick={() => setInputText(q)} className="px-3 py-1.5 bg-slate-950 border border-slate-800 rounded-lg text-xs text-slate-300 hover:border-emerald-500 hover:text-emerald-400 transition-colors flex items-center gap-1">{q} <ArrowRight size={12}/></button>
                                        ))}
                                     </div>
                                </div>
                            )}
                        </>
                    )}
                </div>
            </div>
        ))}
        {agentStage !== AgentStage.IDLE && (
            <div className="flex justify-center my-4">
                <div className="bg-slate-900 border border-emerald-500/30 px-6 py-2 rounded-full text-emerald-400 text-xs font-mono animate-pulse flex items-center gap-2"><Activity size={14}/> {agentStage === AgentStage.ROUTING ? 'ROUTING...' : agentStage === AgentStage.SPECIALIST ? 'CONNECTING AGENT...' : 'ANALYZING...'}</div>
            </div>
        )}
        <div ref={messagesEndRef}/>
      </div>
      <div className="p-4 bg-[#020617] border-t border-slate-800">
         <div className="max-w-4xl mx-auto relative">
            <input type="text" value={inputText} onChange={e => setInputText(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleSendMessage()} placeholder={`[${activeLabel}] Nhập câu hỏi chi tiết...`} className="w-full py-4 pl-4 pr-14 bg-slate-900 border border-slate-700 rounded-xl text-white focus:border-emerald-500 focus:outline-none font-mono"/>
            <button onClick={() => handleSendMessage()} disabled={!inputText.trim()} className="absolute right-2 top-2 bottom-2 bg-emerald-600 hover:bg-emerald-500 text-white rounded-lg px-3"><Send size={18}/></button>
         </div>
      </div>
      <CreditModal isOpen={showCreditModal} onClose={() => setShowCreditModal(false)} onUpgrade={(mode) => { setShowCreditModal(false); onTriggerUpgrade(mode); }} />
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { X, Save, Check, Plus, Trash2, CreditCard } from 'lucide-react';
import { PlanConfig } from '../types';

interface PlanSettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
  plan: PlanConfig | null;
  onSave: (updatedPlan: PlanConfig) => void;
}

export const PlanSettingsModal: React.FC<PlanSettingsModalProps> = ({ isOpen, onClose, plan, onSave }) => {
  const [localPlan, setLocalPlan] = useState<PlanConfig | null>(null);
  const [newFeature, setNewFeature] = useState('');

  useEffect(() => {
    setLocalPlan(plan);
  }, [plan, isOpen]);

  if (!isOpen || !localPlan) return null;

  const handleAddFeature = () => {
    if (newFeature.trim()) {
      setLocalPlan({
        ...localPlan,
        features: [...localPlan.features, newFeature.trim()]
      });
      setNewFeature('');
    }
  };

  const handleRemoveFeature = (index: number) => {
    setLocalPlan({
      ...localPlan,
      features: localPlan.features.filter((_, i) => i !== index)
    });
  };

  const handleSave = () => {
    if (localPlan) {
      onSave(localPlan);
      onClose();
    }
  };

  return (
    <div className="fixed inset-0 z-[70] flex items-center justify-center bg-black/90 backdrop-blur-sm p-4 animate-fade-in">
      <div className="bg-slate-900 w-full max-w-lg rounded-2xl border border-slate-700 shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
        <div className="p-6 border-b border-slate-800 flex justify-between items-center bg-slate-950">
          <div className="flex items-center gap-3">
             <div className={`p-2 rounded-lg bg-${localPlan.color}-900/20 border border-${localPlan.color}-500/30 text-${localPlan.color}-400`}>
                <CreditCard size={20}/>
             </div>
             <div>
                <h3 className="font-bold text-white text-lg">Cấu hình Gói {localPlan.name}</h3>
                <p className="text-xs text-slate-500">ID: {localPlan.id}</p>
             </div>
          </div>
          <button onClick={onClose}><X className="text-slate-500 hover:text-white" size={20} /></button>
        </div>

